const TARGET_STATUS = 'Aguardando cliente';
const IDEMPOTENCY_MARK = 'Cobrança A2.5 disparada em';
const nowBr = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
nowBr.setHours(0, 0, 0, 0);
const twoDaysAgo = new Date(nowBr);
twoDaysAgo.setDate(twoDaysAgo.getDate() - 2);
const twoDaysAgoIso = twoDaysAgo.toISOString().slice(0, 10);
const pickTitle = (page) => {
  for (const prop of Object.values(page.properties || {})) {
    if (prop?.type === 'title') return (prop.title || []).map((item) => item.plain_text || '').join('').trim();
  }
  return '';
};
const pickSelect = (prop) => prop?.select?.name || '';
const pickNumber = (prop) => prop?.number ?? null;
const pickPlainText = (prop) => (prop?.rich_text || []).map((item) => item.plain_text || '').join('');
const out = [];
for (const item of $input.all()) {
  const page = item.json || {};
  const props = page.properties || {};
  const title = pickTitle(page);
  const status = pickSelect(props.Status);
  const due = props['Data prevista']?.date?.start ? String(props['Data prevista'].date.start).slice(0, 10) : '';
  const observacoes_atual = pickPlainText(props['Observações']);
  const clienteRelation = props.Cliente?.relation || [];
  if (status === TARGET_STATUS && due && due <= twoDaysAgoIso && !observacoes_atual.includes(IDEMPOTENCY_MARK) && clienteRelation.length > 0 && !page.archived) {
    out.push({ json: { etapa_page_id: page.id, etapa_nome: title, etapa_sequencia: pickNumber(props['Sequência']), etapa_status: status, data_prevista: due, cliente_page_id: clienteRelation[0].id, cliente_relation_count: clienteRelation.length, observacoes_atual } });
  }
}
return out;

const activeStatuses = new Set(['Em andamento', 'Não iniciado', 'Bloqueado']);
const etapas = $('[Onb A2.5] Filtrar Etapas Elegiveis').all().map((item) => item.json);
const pickTitle = (page) => {
  for (const prop of Object.values(page.properties || {})) {
    if (prop?.type === 'title') return (prop.title || []).map((item) => item.plain_text || '').join('').trim();
  }
  return '';
};
const pickSelect = (prop) => prop?.select?.name || '';
const out = [];
for (const [index, item] of $input.all().entries()) {
  const cliente = item.json || {};
  const etapa = etapas[index];
  if (!etapa) continue;
  const clienteNome = pickTitle(cliente);
  const clienteStatus = pickSelect(cliente.properties?.Status);
  if (!activeStatuses.has(clienteStatus)) continue;
  const number = <OLAVO_PHONE_redacted>;
  if (!number) throw new Error('OLAVO_PHONE ausente');
  const text = `[Onb A2.5] Etapa Aguardando cliente ha >2 dias\netapa=${etapa.etapa_nome} (seq ${etapa.etapa_sequencia})\ndata prevista=${etapa.data_prevista}\ncliente=${clienteNome}\nstatus_cliente=${clienteStatus}\nID da etapa=${etapa.etapa_page_id}\nID do cliente=${etapa.cliente_page_id}\nAção: acionar o cliente off-platform.`;
  out.push({ json: { ...etapa, cliente_nome: clienteNome, cliente_status: clienteStatus, number, text } });
}
return out;

const mensagens = $('[Onb A2.5] Montar Mensagem').all().map((item) => item.json);
const responses = $input.all();
const now = new Date();
const brTimestamp = now.toLocaleString('sv-SE', { timeZone: 'America/Sao_Paulo' }).replace(' ', 'T') + '-03:00';
const out = [];
for (const [index, responseItem] of responses.entries()) {
  const msg = mensagens[index];
  if (!msg) continue;
  const payload = responseItem.json || {};
  const statusCode = Number(payload.statusCode || payload.response?.statusCode || 0);
  const failed = Boolean(payload.error || payload.message || (statusCode && (statusCode < 200 || statusCode >= 300)));
  const evolutionStatus = failed ? 'falhou' : 'ok';
  const detail = statusCode ? `HTTP ${statusCode}` : (failed ? 'erro sem status HTTP' : '');
  const linhaNova = `Cobrança A2.5 disparada em ${brTimestamp}. Status Evolution: ${evolutionStatus}${detail ? ` (${detail})` : ''}.`;
  const observacoes_atual = msg.observacoes_atual || '';
  const observacoes_finais = observacoes_atual ? `${observacoes_atual}\n${linhaNova}` : linhaNova;
  out.push({ json: { ...msg, evolution_status: evolutionStatus, evolution_detail: detail, linha_nova: linhaNova, observacoes_finais } });
}
return out;

